<?php
namespace App\Models;use App\Models\Concerns\BelongsToWorkspace;use Illuminate\Database\Eloquent\Model;
class WorkProof extends Model{use BelongsToWorkspace;public const TYPES=['file','screenshot','image','url','note','before_after'];public const STATUSES=['submitted','approved','rejected'];protected $fillable=['workspace_id','task_id','daily_report_id','submitted_by','proof_type','title','note','url','file_path','file_disk','original_name','mime_type','file_size','status','reviewed_by','reviewed_at','rejection_reason'];protected function casts():array{return['reviewed_at'=>'datetime'];}public function task(){return $this->belongsTo(Task::class);}public function dailyReport(){return $this->belongsTo(DailyReport::class);}public function submitter(){return $this->belongsTo(User::class,'submitted_by');}public function reviewer(){return $this->belongsTo(User::class,'reviewed_by');}}
